const input = $input.first().json;

// AI Agent (LangChain toolWorkflow) truyen input duoi nhieu dang (copy pattern ST-013):
//  1. { user_message: "...", chat_id: 123 }
//  2. { params: { user_message, chat_id } }
//  3. { text: "..." }
//  4. { message: "..." }
//  5. { query: "..." }
//  6. "<plain string>"
//  7. {} (empty)
const candidates = [input, input.params || {}, input.input || {}, input.data || {}];
let userMessage = '';
let chatId = '';

for (const obj of candidates) {
  if (!obj || typeof obj !== 'object') continue;
  userMessage = userMessage
    || obj.user_message
    || obj.text
    || obj.message
    || obj.query
    || obj.content
    || obj.input
    || '';
  chatId = chatId
    || obj.chat_id
    || obj.chatId
    || obj.chat_id_str
    || '';
}

if (!userMessage && typeof input === 'string') {
  userMessage = input;
}
if (!userMessage && input.json && typeof input.json === 'string') {
  userMessage = input.json;
}

// NEW: Try to parse userMessage as JSON if it is a JSON string
let parsedJson = null;
if (typeof userMessage === 'string' && userMessage.trim().startsWith('{')) {
  try {
    parsedJson = JSON.parse(userMessage);
  } catch (e) {
    // Ignore parse error
  }
}

if (parsedJson && typeof parsedJson === 'object') {
  userMessage = parsedJson.user_message || parsedJson.text || parsedJson.message || parsedJson.query || userMessage;
  chatId = chatId || parsedJson.chat_id || parsedJson.chatId || parsedJson.chat_id_str || '';
}

if (!chatId || String(chatId).trim() === '') {
  return [];
}

const trimmed = String(userMessage || '').trim();
const isEmpty = trimmed.length === 0;

return [{
  json: {
    user_message: trimmed,
    chat_id: String(chatId || ''),
    session_id: input.session_id || (input.params && input.params.session_id) || '',
    is_empty_input: isEmpty,
  }
}];

const extract = $('Extract Input').first().json;

// Fail-closed: khong co chat_id thi return [] de workflow ket thuc, khong goi Telegram
if (!extract.chat_id || String(extract.chat_id).trim() === '') {
  return [];
}

return [{
  json: {
    success: false,
    status: 'empty_input',
    chat_id: extract.chat_id,
    text: '🤔 *Bạn muốn đặt lịch hẹn nào?*\n\nMình giúp tạo sự kiện trên Google Calendar. Bạn nói rõ:\n• *Tiêu đề* (vd: họp team, gặp khách)\n• *Thời gian* (vd: 10h sáng mai, 14h chiều thứ 6 tuần sau)\n• *Địa điểm*, *mô tả* (nếu có)\n\nVí dụ: "Đặt lịch họp team từ 10h đến 11h ngày mai, tại phòng họp A"'
  }
}];

